import { useStore } from './store';

export const SubmitButton = () => {
    const { nodes, edges } = useStore();

    const handleSubmit = async () => {
        const formData = new FormData();
        formData.append('nodes', JSON.stringify(nodes.map(n => n.id)));
        formData.append('edges', JSON.stringify(edges.map(e => `${e.source}->${e.target}`)));

        try {
            const response = await fetch('http://127.0.0.1:8000/pipelines/parse', {
                method: 'POST',
                mode: 'cors', // Explicitly allow CORS
                body: formData,
            });

            if (!response.ok) {
                const errorText = await response.text();
                throw new Error(`Server error: ${response.status} - ${errorText}`);
            }

            const data = await response.json();
            alert(`Pipeline Analysis:\nNodes: ${data.num_nodes}\nEdges: ${data.num_edges}\nIs DAG: ${data.is_dag}`);
        } catch (error) {
            console.error("Submission failed:", error);
            alert(`Failed to connect to backend: ${error.message}`);
        }
    };

    return (
        <div style={{ display: 'flex', justifyContent: 'center', marginTop: '20px' }}>
            <button onClick={handleSubmit}>Submit Pipeline</button>
        </div>
    );
};
